import React, { useEffect, useState, useRef } from "react";

export default function DashboardCard({ title, value, growth, icon }) {
  const [displayValue, setDisplayValue] = useState(0);
  const frame = useRef();

  // Animate numbers smoothly using requestAnimationFrame
  useEffect(() => {
    if (typeof value !== "number") return;

    let start = 0;
    const duration = 800; // total duration in ms
    const startTime = performance.now();

    const animate = (time) => {
      const progress = Math.min((time - startTime) / duration, 1);
      setDisplayValue(Math.floor(progress * value));
      if (progress < 1) frame.current = requestAnimationFrame(animate);
      else setDisplayValue(value);
    };

    frame.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(frame.current);
  }, [value]);

  const isPositive = growth >= 0;

  return (
    <div className="relative bg-white/10 backdrop-blur-lg border border-yellow-400 p-6 rounded-2xl text-center text-white shadow-xl transition transform hover:scale-105 hover:shadow-2xl overflow-hidden">
      
      {/* Optional Icon */}
      {icon && (
        <div className="absolute top-4 right-4 text-3xl opacity-20">{icon}</div>
      )}

      {/* Title */}
      <div className="text-sm text-white/70 tracking-wide uppercase">
        {title}
      </div>

      {/* Value */}
      <div className="text-4xl md:text-5xl font-bold mt-2">
        {typeof value === "number" ? `₹ ${displayValue.toLocaleString()}` : value}
      </div>

      {/* Growth Indicator */}
      {growth !== undefined && (
        <div
          className={`mt-3 text-sm font-semibold flex items-center justify-center space-x-1 ${
            isPositive ? "text-green-400" : "text-red-400"
          }`}
          title="Growth compared to previous period"
        >
          <span>{isPositive ? "▲" : "▼"}</span>
          <span>{Math.abs(growth)}%</span>
        </div>
      )}
    </div>
  );
}
